module d_flip_flop (  
    input clk,  
    input reset,  
    input D,  
    output reg Q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            Q <= 0;  
        end else begin  
            Q <= D;  
        end  
    end  
endmodule
